input.content:
import { cacheTag } from 'next/cache';

export interface Post {
  id: number;
  title: string;
  content: string;
  createdAt: Date;
}

const posts: Post[] = [
  {
    id: 1,
    title: 'First Post',
    content: 'This is a sample post to demonstrate caching.',
    createdAt: new Date('2026-07-01'),
  },
];

let nextId = 2;

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');
  return posts;
}

export async function createPost(title: string, content: string): Promise<Post> {
  const post: Post = {
    id: nextId++,
    title,
    content,
    createdAt: new Date(),
  };
  posts.push(post);
  return post;
}

'use server';

import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { createPost } from '@/lib/posts';

export async function createPostAction(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  await createPost(title, content);

  // Immediately expire the "posts" cache tag so the next page load
  // fetches fresh data instead of serving stale cached content.
  updateTag('posts');

  redirect('/');
}

