import { getPosts } from '@/lib/posts';
import { createPostAction } from '@/app/actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: 24 }}>
      <h1>Posts</h1>

      <form action={createPostAction}>
        <div style={{ marginBottom: 12 }}>
          <label htmlFor="title">
            Title
            <br />
            <input id="title" name="title" required style={{ width: '100%', marginTop: 4 }} />
          </label>
        </div>
        <div style={{ marginBottom: 12 }}>
          <label htmlFor="content">
            Content
            <br />
            <textarea id="content" name="content" required rows={4} style={{ width: '100%', marginTop: 4 }} />
          </label>
        </div>
        <button type="submit">Create Post</button>
      </form>

      <hr style={{ margin: '24px 0' }} />

      <h2>All Posts</h2>
      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li key={post.id} style={{ border: '1px solid #ccc', borderRadius: 8, padding: 16, marginBottom: 12 }}>
              <h3 style={{ margin: '0 0 4px' }}>{post.title}</h3>
              <p style={{ margin: '0 0 4px', color: '#555' }}>{post.content}</p>
              <small style={{ color: '#999' }}>{post.createdAt.toLocaleDateString()}</small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

